Problem
 Given a String: "abbababacfefg" (Can be string of any length)
 An integer N = length of the string
 and an Integer k: 2

 Find the largest window that will always have at most k distinct characters

 Eg:
 input = "abbaacac"
 length = 8
 k = 2

 Window Size 2
 "ab" -> 2
  "bb" -> 1
  "ba" -> 2
  "aa" -> 1
  "ac" -> 2
  "ca" -> 2
  "ac"-> 2
 Valid

 Window Size 3
 "abb" -> 2
  "bba" -> 2
  "baa" -> 2
  "aac" -> 1
  "aca" -> 2
  "cac" -> 2
 Valid

 Window Size 4
 "abba" -> 2
  "bbab" -> 2
  "baac" -> 3 > k X

 Invalid

 Output:-
 3

 3 Is the largest Window size we can fit for the given problem


 ANSWER:-
 ```
 import java.util.*;

 public class LargestWindowWithKDistinct 
 { 
  public static int findMaxWindow(String s, int n, int k) {
  int low = 1, high = n, 
  result = 0;
  while (low <= high) 
  {
  int mid = (low + high) / 2;

  if (isValid(s, mid, k)) 
  {
  result = mid; // mid is valid, try to go higher
  low = mid + 1;
  } else {
  high = mid - 1; // mid is not valid, go lower
  }
  }

  return result;
  }

  private static boolean isValid(String s, int windowSize, int k) 
  {
  Map<Character, Integer> freqMap = new HashMap<>();
  int l=0;
  int r=0;

  // Initialize the frequency map for the first 'k' characters
  while(r < windowSize)
  {
  char cR = s.charAt(r++);
  freqMap.put(cR, freqMap.getOrDefault(cR, 0) + 1);

  if(freqMap.size() > k)
  return false;
  }

  //Slide window
  while(r < s.length())
  {
  char cR = s.charAt(r++);
  char cL = s.charAt(l++);
  freqMap.put(cR, freqMap.getOrDefault(cR, 0) + 1);

  freqMap.put(cL, freqMap.get(cL) - 1);
  if (freqMap.get(cL) == 0) { 
  freqMap.remove(cL);
  }

  if(freqMap.size() > k)
  return false;
  }

  return true;
  }

  // Example usage
  public static void main(String[] args) {
  String input = "abbaacac";
  int k = 2;
  int result = findMaxWindow(input, input.length(), k);
  System.out.println("Maximum valid window size: " + result);
  }
 }
 ```
